const project = $input.first().json;
const status = project.Status.select.name;

const messages = {
  'Design': {
    subject: 'Design Phase Started - Mockups Coming Soon',
    body: `Your project has moved to the Design phase! Our AI is generating initial mockups based on your requirements. You'll have designs to review within 48 hours.`
  },
  'Development': {
    subject: 'Development Started - Building Your Solution',
    body: `Exciting news! We've started building your project. Our AI development pipeline is working on your solution. Expect daily progress updates.`
  },
  'Review': {
    subject: 'Ready for Your Review - Check It Out!',
    body: `Your project is ready for review! Check out the preview link below and let us know what you think. Two rounds of revisions are included.`
  },
  'Launch': {
    subject:

,
    body: `Congratulations! Your project is now live. All systems operational. Final invoice has been sent. Thank you for choosing Craft Mode!`
  }
};

return [{
  json: {
    ...project,
    notification: messages[status] || null,
    shouldNotify: !!messages[status]
  }
}];

